### Property Tests

```rust
#[cfg(test)]
mod property_tests {
    use super::*;
    use proptest::prelude::*;

    fn arb_style() -> impl Strategy<Value = Style> {
        (
            proptest::option::of(any::<u32>().prop_map(PackedRgba)),
            proptest::option::of(any::<u32>().prop_map(PackedRgba)),
            proptest::option::of(any::<u16>().prop_map(StyleFlags)),
        ).prop_map(|(fg, bg, attrs)| Style { fg, bg, attrs, underline_color: None })
    }

    proptest! {
        #[test]
        fn merge_identity(s in arb_style()) {
            // Merging with empty style returns self
            let empty = Style::default();
            prop_assert_eq!(s.merge(&empty), s);
        }

        #[test]
        fn merge_deterministic(a in arb_style(), b in arb_style()) {
            // Same inputs always produce same output
            let merged1 = a.merge(&b);
            let merged2 = a.merge(&b);
            prop_assert_eq!(merged1, merged2);
        }
    }
}
