### Performance Tests

```rust
#[test]
fn test_style_merge_performance() {
    let parent = Style::new().fg(PackedRgba::RED).bold();
    let child = Style::new().bg(PackedRgba::BLUE).italic();

    let start = std::time::Instant::now();
    for _ in 0..1_000_000 {
        let _ = child.merge(&parent);
    }
    let elapsed = start.elapsed();

    // 1M merges should be < 50ms (< 50ns each)
    assert!(elapsed.as_millis() < 50, "Merge too slow: {:?}", elapsed);
}
```

